def extract_tweet_text(html):
    soup = BeautifulSoup(html, "html.parser")
    try:
        tweet_div = soup.find("div", {"data-testid": "tweetText"})
        tweet_parts = []

        for el in tweet_div.descendants:
            if el.name == "span":
                tweet_parts.append(el.get_text())
            elif el.name == "img":
                alt = el.get("alt", "")
                if alt:
                    tweet_parts.append(alt)

        tweet_text = "".join(tweet_parts).strip()
        tweet_text_demojized = emoji.demojize(tweet_text)

        return tweet_text_demojized

    except AttributeError:
        return None


def extract_analytics(html):
    soup = BeautifulSoup(html, "html.parser")
    views_div = soup.find_all("div", {"aria-label": True})
    analytics_aria = views_div[-1]
    analytics = analytics_aria.get("aria-label", "")

    return analytics


def extract_lang(html):
    soup = BeautifulSoup(html, "html.parser")
    tweet_div = soup.find("div", {"data-testid": "tweetText"})

    if tweet_div:
        lang = tweet_div.get("lang")
    else:
        lang = None

    return lang


def extract_time(html, time_zone):
    soup = BeautifulSoup(html, "html.parser")
    time_element = soup.find("time")

    if time_element is None:
        return None

    datetime_value = time_element["datetime"]

    # remove the z at the end and convert to datetime object
    datetime_value = datetime_value.rstrip("Z")

    # convert to time zone
    dt_object = datetime.fromisoformat(datetime_value)
    time_zone_dt = dt_object.replace(tzinfo=time_zone)
    return time_zone_dt


